using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;

namespace ResearchAgent.Tools;

public static partial class WebSearchTool
{
    private static readonly HttpClient s_http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" }
        },
        Timeout = TimeSpan.FromSeconds(15)
    };

    [Description("Search the web for information about a query. Returns a list of result titles, URLs, and snippets.")]
    public static async Task<string> SearchWeb(
        [Description("The search query to look up")] string query)
    {
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  🔍 Searching: \"{query}\"");
        Console.ResetColor();

        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await s_http.GetStringAsync(url);

            var results = ParseSearchResults(html);

            if (results.Count == 0)
                return $"No results found for: {query}";

            return string.Join("\n\n", results.Take(5).Select((r, i) =>
                $"[{i + 1}] {r.Title}\n    URL: {r.Url}\n    {r.Snippet}"));
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch and read the text content of a web page given its URL. Use this to get detailed information from a search result.")]
    public static async Task<string> ReadWebPage(
        [Description("The full URL of the page to read")] string url)
    {
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  🌐 Reading: {url}");
        Console.ResetColor();

        try
        {
            var html = await s_http.GetStringAsync(url);
            var text = StripHtml(html);

            // Limit to a reasonable length for the LLM context
            const int maxLen = 3000;
            if (text.Length > maxLen)
                text = text[..maxLen] + "\n... [truncated]";

            return string.IsNullOrWhiteSpace(text)
                ? "Could not extract meaningful text from the page."
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to read page: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseSearchResults(string html)
    {
        var results = new List<SearchResult>();
        var linkMatches = ResultLinkRegex().Matches(html);

        foreach (Match m in linkMatches)
        {
            var rawUrl = WebUtility.HtmlDecode(m.Groups[1].Value);
            var title = StripHtml(m.Groups[2].Value).Trim();

            if (string.IsNullOrWhiteSpace(title) || rawUrl.Contains("duckduckgo.com"))
                continue;

            // DuckDuckGo wraps URLs in a redirect; extract the actual URL
            var actualUrl = ExtractRedirectUrl(rawUrl) ?? rawUrl;

            results.Add(new SearchResult { Title = title, Url = actualUrl });
        }

        // Try to grab snippets from the result blocks
        var snippetMatches = SnippetRegex().Matches(html);
        for (int i = 0; i < Math.Min(snippetMatches.Count, results.Count); i++)
        {
            results[i].Snippet = StripHtml(snippetMatches[i].Groups[1].Value).Trim();
        }

        return results;
    }

    private static string? ExtractRedirectUrl(string url)
    {
        var match = UddhRegex().Match(url);
        return match.Success ? WebUtility.UrlDecode(match.Groups[1].Value) : null;
    }

    private static string StripHtml(string html)
    {
        var text = HtmlTagRegex().Replace(html, " ");
        text = WebUtility.HtmlDecode(text);
        text = WhitespaceRegex().Replace(text, " ").Trim();
        return text;
    }

    [GeneratedRegex("""<a[^>]+class="result__a"[^>]*href="([^"]*)"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex ResultLinkRegex();

    [GeneratedRegex("""<a[^>]+class="result__snippet"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex("""uddg=([^&]+)""")]
    private static partial Regex UddhRegex();

    [GeneratedRegex("""<[^>]+>""")]
    private static partial Regex HtmlTagRegex();

    [GeneratedRegex("""\s+""")]
    private static partial Regex WhitespaceRegex();

    private sealed class SearchResult
    {
        public string Title { get; set; } = "";
        public string Url { get; set; } = "";
        public string Snippet { get; set; } = "";
    }
}

using System.ComponentModel;

namespace ResearchAgent.Tools;

public static class NoteTool
{
    private static readonly List<Note> s_notes = [];

    [Description("Save a research note with a topic tag. Use this to record key findings during research.")]
    public static string SaveNote(
        [Description("A short topic label for the note (e.g. 'definition', 'history', 'key-stats')")] string topic,
        [Description("The content of the note")] string content)
    {
        var note = new Note(topic, content, DateTime.UtcNow);
        s_notes.Add(note);

        Console.ForegroundColor = ConsoleColor.DarkCyan;
        Console.WriteLine($"  📝 Note saved: [{topic}] {Truncate(content, 60)}");
        Console.ResetColor();

        return $"Note #{s_notes.Count} saved under topic '{topic}'.";
    }

    [Description("Retrieve all saved research notes. Use this when you are ready to compile your summary.")]
    public static string GetAllNotes()
    {
        if (s_notes.Count == 0)
            return "No notes have been saved yet.";

        Console.ForegroundColor = ConsoleColor.DarkCyan;
        Console.WriteLine($"  📋 Retrieving {s_notes.Count} note(s)");
        Console.ResetColor();

        return string.Join("\n\n", s_notes.Select((n, i) =>
            $"Note #{i + 1} [{n.Topic}] ({n.Timestamp:HH:mm:ss UTC})\n{n.Content}"));
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "...";

    private sealed record Note(string Topic, string Content, DateTime Timestamp);
}

