using Microsoft.Extensions.AI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// --- Build chat client with automatic function invocation ---
IChatClient chatClient = new OpenAIChatClient(
        new OpenAI.Chat.ChatClient(model, new System.ClientModel.ApiKeyCredential(apiKey)))
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// --- Register tools the agent can use ---
ChatOptions options = new()
{
    Tools =
    [
        AIFunctionFactory.Create(WebSearchTool.SearchWeb),
        AIFunctionFactory.Create(WebSearchTool.ReadWebPage),
        AIFunctionFactory.Create(NoteTool.SaveNote),
        AIFunctionFactory.Create(NoteTool.GetAllNotes),
    ],
    Temperature = 0.2f,
};

// --- Get research topic ---
Console.ForegroundColor = ConsoleColor.White;
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        🔬  AI Research Agent  🔬        ║");
Console.WriteLine("╠══════════════════════════════════════════╣");
Console.WriteLine("║  I'll search the web and compile notes   ║");
Console.WriteLine("║  to produce a research summary for you.  ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.ResetColor();

Console.Write("\nEnter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

// --- Agent system prompt ---
List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a thorough research agent. When given a topic, you MUST follow this process:

        1. SEARCH: Use SearchWeb at least 3 times with different, diverse queries to gather
           broad information about the topic. Vary your queries (e.g., overview, recent news,
           expert opinions, statistics).

        2. READ: Use ReadWebPage on 1-2 of the most promising URLs from your search results
           to get deeper information.

        3. TAKE NOTES: After each search or page read, use SaveNote to record the key findings.
           Tag each note with a relevant topic label.

        4. COMPILE: Once you have gathered enough information, call GetAllNotes to retrieve
           everything, then write a well-structured research summary.

        Your final summary should include:
        - An overview/definition of the topic
        - Key facts and statistics
        - Recent developments or news
        - Different perspectives or viewpoints
        - A conclusion with key takeaways

        Always cite your sources by including URLs where applicable.
        """),
    new(ChatRole.User, $"Please research the following topic thoroughly: {topic}"),
];

// --- Run the agent loop ---
Console.ForegroundColor = ConsoleColor.Green;
Console.WriteLine($"\n▶ Researching: {topic}\n");
Console.ResetColor();

var response = await chatClient.GetResponseAsync(messages, options);

// --- Display final summary ---
Console.ForegroundColor = ConsoleColor.White;
Console.WriteLine("\n════════════════════════════════════════════");
Console.WriteLine("               RESEARCH SUMMARY             ");
Console.WriteLine("════════════════════════════════════════════\n");
Console.ResetColor();

Console.WriteLine(response.Text);

Console.ForegroundColor = ConsoleColor.DarkGray;
Console.WriteLine($"\n[Completed — Model: {model}, Finish reason: {response.FinishReason}]");
Console.ResetColor();

